Here's an improved MQL5 Expert Advisor that buys 1.0 lot when a candle closes above the 50-period EMA, with enhancements to prevent duplicate trades and handle new bars:

```mql5
//+------------------------------------------------------------------+
//|                                         EMA_Buy_EA.mq5           |
//|                        Copyright 2024, Your Name                 |
//|                                       https://www.yourwebsite.com|
//+------------------------------------------------------------------+
#property copyright "Copyright 2024, Your Name"
#property link      "https://www.yourwebsite.com"
#property version   "1.00"
#property strict

// Input parameters
input double LotSize = 1.0;          // Lot size for trade
input int    EMA_Period = 50;        // EMA period
input ENUM_MA_METHOD MA_Method = MODE_EMA; // EMA method
input ENUM_APPLIED_PRICE Applied_Price = PRICE_CLOSE; // Price source

// Global variables
datetime LastBarTime;                // To track new bar

//+------------------------------------------------------------------+
//| Expert initialization function                                   |
//+------------------------------------------------------------------+
int OnInit()
{
   // Initialize last bar time
   LastBarTime = iTime(_Symbol, _Period, 0);
   return(INIT_SUCCEEDED);
}

//+------------------------------------------------------------------+
//| Expert tick function                                             |
//+------------------------------------------------------------------+
void OnTick()
{
   // Check for new bar
   if(!IsNewBar())
      return;

   // Check trading conditions
   if(CheckBuyCondition())
      ExecuteBuyTrade();
}

//+------------------------------------------------------------------+
//| Check if a new bar has formed                                    |
//+------------------------------------------------------------------+
bool IsNewBar()
{
   datetime currentBarTime = iTime(_Symbol, _Period, 0);
   if(currentBarTime != LastBarTime)
   {
      LastBarTime = currentBarTime;
      return true;
   }
   return false;
}

//+------------------------------------------------------------------+
//| Check if buy condition is met: close above 50 EMA                |
//+------------------------------------------------------------------+
bool CheckBuyCondition()
{
   // Get EMA value for current bar (index 0)
   double emaValue = iMA(_Symbol, _Period, EMA_Period, 0, MA_Method, Applied_Price, 0);

   // Get close price of previous bar (index 1) because we check after bar closes
   double closePrice = iClose(_Symbol, _Period, 1);

   // Condition: previous candle closed above EMA
   if(closePrice > emaValue)
      return true;

   return false;
}

//+------------------------------------------------------------------+
//| Check if there is already an open buy position                   |
//+------------------------------------------------------------------+
bool BuyPositionExists()
{
   for(int i = PositionsTotal() - 1; i >= 0; i--)
   {
      if(PositionGetSymbol(i) == _Symbol && PositionGetInteger(POSITION_TYPE) == POSITION_TYPE_BUY)
         return true;
   }
   return false;
}

//+------------------------------------------------------------------+
//| Execute buy trade                                                |
//+------------------------------------------------------------------+
void ExecuteBuyTrade()
{
   // Check if buy position already exists
   if(BuyPositionExists())
   {
      Print("Buy position already exists. Skipping new trade.");
      return;
   }

   // Prepare trade request
   MqlTradeRequest request;
   MqlTradeResult result;
   ZeroMemory(request);
   ZeroMemory(result);

   request.action    = TRADE_ACTION_DEAL;
   request.symbol    = _Symbol;
   request.volume    = LotSize;
   request.type      = ORDER_TYPE_BUY;
   request.price     = SymbolInfoDouble(_Symbol, SYMBOL_ASK);
   request.deviation = 10;
   request.magic     = 12345;
   request.comment   = "EMA Buy Signal";

   // Send trade request
   if(!OrderSend(request, result))
   {
      Print("OrderSend failed: Error ", GetLastError(), ", retcode: ", result.retcode);
      return;
   }

   // Check result
   if(result.retcode == TRADE_RETCODE_DONE)
      Print("Buy order opened successfully. Ticket: ", result.order);
   else
      Print("Order failed. Retcode: ", result.retcode);
}
```

**Key Improvements:**
1. **New Bar Detection**: The `IsNewBar()` function ensures the EA only checks conditions once per candle, preventing multiple signals within the same bar.
2. **Existing Position Check**: `BuyPositionExists()` checks if a buy position is already open for the symbol, avoiding duplicate trades.
3. **Proper Error Handling**: Uses `OrderSend` with `MqlTradeRequest` and `MqlTradeResult` for robust error reporting.
4. **Flexible Inputs**: Allows customization of EMA period, method, and applied price via input parameters.
5. **Correct Bar Reference**: Checks the previous candle's close (index 1) against the EMA at the current bar (index 0), which is standard for after-close conditions.

**Usage Notes:**
- This EA will open a buy trade of 1.0 lot when the previous candle closes above the 50 EMA.
- It only triggers once per new bar and if no buy position is already open.
- Always test in a demo account before live trading and consider adding stop-loss and take-profit levels as needed.

In MQL5, there are several ways to create a "profitchart" depending on what you need. Here are three common approaches:

## 1. **Simple Profit/Loss Display Indicator**
This indicator shows current account profit/loss on the chart:

```mql5
//+------------------------------------------------------------------+
//|                                          SimpleProfitChart.mq5   |
//|                        Copyright 2024                            |
//+------------------------------------------------------------------+
#property copyright "Copyright 2024"
#property link      "https://www.mql5.com"
#property version   "1.00"
#property indicator_separate_window
#property indicator_buffers 1
#property indicator_plots   1
#property indicator_label1  "Profit/Loss"
#property indicator_type1   DRAW_LINE
#property indicator_color1  clrDodgerBlue
#property indicator_style1  STYLE_SOLID
#property indicator_width1  2

double ProfitBuffer[];
string comment_text;

//+------------------------------------------------------------------+
//| Custom indicator initialization function                         |
//+------------------------------------------------------------------+
int OnInit()
{
   SetIndexBuffer(0, ProfitBuffer, INDICATOR_DATA);
   IndicatorSetString(INDICATOR_SHORTNAME, "Profit Chart");
   IndicatorSetInteger(INDICATOR_DIGITS, 2);
   return(INIT_SUCCEEDED);
}

//+------------------------------------------------------------------+
//| Custom indicator iteration function                              |
//+------------------------------------------------------------------+
int OnCalculate(const int rates_total,
                const int prev_calculated,
                const datetime &time[],
                const double &open[],
                const double &high[],
                const double &low[],
                const double &close[],
                const long &tick_volume[],
                const long &volume[],
                const int &spread[])
{
   int start = prev_calculated;
   if(start < 0) return(0);
   if(start == 0) start = 1;

   for(int i = start; i < rates_total && !IsStopped(); i++)
   {
      double profit = AccountInfoDouble(ACCOUNT_PROFIT);
      ProfitBuffer[i] = profit;
   }

   // Update chart comment with current profit
   double current_profit = AccountInfoDouble(ACCOUNT_PROFIT);
   double equity = AccountInfoDouble(ACCOUNT_EQUITY);
   double balance = AccountInfoDouble(ACCOUNT_BALANCE);

   comment_text = StringFormat("Profit: $%.2f | Equity: $%.2f | Balance: $%.2f", 
                               current_profit, equity, balance);
   Comment(comment_text);

   return(rates_total);
}
```

## 2. **Equity Curve Chart Script**
This script draws the equity curve directly on the price chart:

```mql5
//+------------------------------------------------------------------+
//|                                          EquityCurveChart.mq5    |
//|                        Copyright 2024                            |
//+------------------------------------------------------------------+
#property script_show_inputs
#property strict

input color LineColor = clrBlue;      // Line color
input int   LineWidth = 2;            // Line width
input bool  ShowLabels = true;        // Show profit labels

//+------------------------------------------------------------------+
//| Script program start function                                    |
//+------------------------------------------------------------------+
void OnStart()
{
   // Get history of closed positions
   HistorySelect(0, TimeCurrent());
   int total = HistoryDealsTotal();

   if(total == 0)
   {
      Print("No closed positions found");
      return;
   }

   double cumulative_profit = 0;
   string line_name = "EquityCurve_";
   string label_name = "ProfitLabel_";

   // Clear previous drawings
   ObjectsDeleteAll(0, line_name);
   ObjectsDeleteAll(0, label_name);

   for(int i = 0; i < total; i++)
   {
      ulong ticket = HistoryDealGetTicket(i);
      if(ticket > 0)
      {
         double profit = HistoryDealGetDouble(ticket, DEAL_PROFIT);
         double commission = HistoryDealGetDouble(ticket, DEAL_COMMISSION);
         double swap = HistoryDealGetDouble(ticket, DEAL_SWAP);
         double fee = HistoryDealGetDouble(ticket, DEAL_FEE);

         double total_profit = profit + commission + swap + fee;
         cumulative_profit += total_profit;

         datetime time = (datetime)HistoryDealGetInteger(ticket, DEAL_TIME);

         // Draw point on chart
         string point_name = line_name + IntegerToString(i);
         ObjectCreate(0, point_name, OBJ_ARROW_RIGHT_PRICE, 0, time, cumulative_profit);
         ObjectSetInteger(0, point_name, OBJPROP_COLOR, LineColor);
         ObjectSetInteger(0, point_name, OBJPROP_WIDTH, LineWidth);

         // Add label if enabled
         if(ShowLabels)
         {
            string lbl_name = label_name + IntegerToString(i);
            ObjectCreate(0, lbl_name, OBJ_TEXT, 0, time, cumulative_profit);
            ObjectSetString(0, lbl_name, OBJPROP_TEXT, DoubleToString(cumulative_profit, 2));
            ObjectSetInteger(0, lbl_name, OBJPROP_COLOR, LineColor);
            ObjectSetInteger(0, lbl_name, OBJPROP_FONTSIZE, 8);
         }
      }
   }

   // Connect points with lines
   for(int i = 1; i < total; i++)
   {
      string line_obj_name = "EquityLine_" + IntegerToString(i);
      ObjectCreate(0, line_obj_name, OBJ_TREND, 0, 0, 0);
      ObjectSetInteger(0, line_obj_name, OBJPROP_COLOR, LineColor);
      ObjectSetInteger(0, line_obj_name, OBJPROP_WIDTH, LineWidth);
