    public class EMA50BuyStrategy : Strategy
    {
        #region Variables
        private int emaPeriod = 50;
        private double positionSize = 1.0; // Lot size
        #endregion

        protected override void OnStateChange()
        {
            if (State == State.SetDefaults)
            {
                Description = @"Strategy that buys when price closes above 50 EMA";
                Name = "EMA50BuyStrategy";
                Calculate = Calculate.OnBarClose;
                EntriesPerDirection = 1;
                EntryHandling = EntryHandling.AllEntries;
                IsExitOnSessionCloseStrategy = true;
                ExitOnSessionCloseSeconds = 30;
                IsFillLimitOnTouch = false;
                MaximumBarsLookBack = MaximumBarsLookBack.TwoHundredFiftySix;
                OrderFillResolution = OrderFillResolution.Standard;
                Slippage = 0;
                StartBehavior = StartBehavior.WaitUntilFlat;
                TimeInForce = TimeInForce.Gtc;
                TraceOrders = false;
                RealtimeErrorHandling = RealtimeErrorHandling.StopCancelClose;
                StopTargetHandling = StopTargetHandling.PerEntryExecution;
                BarsRequiredToTrade = 50;
            }
            else if (State == State.Configure)
            {
                // Add EMA indicator
                AddChartIndicator(EMA(emaPeriod));
            }
        }

        protected override void OnBarUpdate()
        {
            // Ensure we have enough bars
            if (CurrentBar < emaPeriod)
